import React from 'react';
import df from '../../styles/documentForm.module.css';
import { useVoucherHeaderCompact } from './useVoucherHeaderCompact';
import { VoucherFormRow } from './VoucherFormRow';

export type SalesVoucherHeaderCompact = ReturnType<typeof useVoucherHeaderCompact> & {
  formRowStyles: { row4: string };
};

export const SalesVoucherHeaderSection: React.FC<{
  title: string;
  testIdPrefix: string;
  headerExpanded: boolean;
  setHeaderExpanded: React.Dispatch<React.SetStateAction<boolean>>;
  children: (compact: SalesVoucherHeaderCompact) => React.ReactNode;
}> = ({ title, testIdPrefix, headerExpanded, setHeaderExpanded, children }) => {
  const compact = useVoucherHeaderCompact({
    enabled: true,
    headerExpanded,
    styles: {
      field: df.field,
      headerCompactHidden: df.headerCompactHidden,
      headerCompactActive: df.headerCompactActive,
    },
  });

  const formRowStyles = { row4: df.row4 };
  const sectionClass = [df.section, compact.headerCompactSectionClass].filter(Boolean).join(' ');

  return (
    <div className={sectionClass} data-testid={`${testIdPrefix}-section-header`}>
      <div className={df.sectionTitleRow}>
        <h2 className={df.sectionTitle}>{title}</h2>
        <button
          type="button"
          className={df.headerToggleBtn}
          data-testid={`${testIdPrefix}-header-${headerExpanded ? 'collapse' : 'expand'}`}
          aria-expanded={headerExpanded}
          onClick={() => setHeaderExpanded(v => !v)}
        >
          <span className={df.headerToggleIcon} aria-hidden>
            <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
          </span>
          {headerExpanded ? 'Thu gọn' : 'Mở rộng'}
        </button>
      </div>
      <div className={df.headerFieldsFlow}>
        {children({ ...compact, formRowStyles })}
      </div>
    </div>
  );
};

export { VoucherFormRow };
